package com.example.demo.services;import com.example.demo.dto.MovimientoCuentaDTO;import com.example.demo.models.*;import com.example.demo.repository.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.math.BigDecimal;import java.time.LocalDateTime;import java.util.List;
@Service public class CuentaCorrienteService{private final ClienteRepository clientes;private final PersonaRepository personas;private final MovimientoCuentaRepository movimientos;private final ReglasOperativasService reglas;private final AuditoriaService auditoria;public CuentaCorrienteService(ClienteRepository clientes,PersonaRepository personas,MovimientoCuentaRepository movimientos,ReglasOperativasService reglas,AuditoriaService auditoria){this.clientes=clientes;this.personas=personas;this.movimientos=movimientos;this.reglas=reglas;this.auditoria=auditoria;}
    @Transactional public void registrarVenta(Venta venta,Long usuarioId){if(!reglas.obtener().fiadoHabilitado())throw new IllegalStateException("La cuenta corriente no está habilitada");Cliente c=venta.getCliente();if(c==null)throw new IllegalArgumentException("La venta fiada requiere un cliente");BigDecimal limite=c.getLimiteCredito().signum()>0?c.getLimiteCredito():reglas.obtener().limiteCreditoPredeterminado();BigDecimal nuevo=c.getSaldoCuenta().add(venta.getTotal());if(limite.signum()>0&&nuevo.compareTo(limite)>0)throw new IllegalStateException("El cliente supera su límite de crédito");c.setSaldoCuenta(nuevo);venta.setMontoFiado(venta.getTotal());guardar(c,MovimientoCuenta.Tipo.VENTA_FIADA,venta.getTotal(),"Venta "+venta.getNumeroComprobante(),venta,usuarioId);}
    @Transactional public MovimientoCuentaDTO registrarPago(Long clienteId,BigDecimal monto,String descripcion,Long usuarioId){Cliente c=cliente(clienteId);if(monto==null||monto.signum()<=0)throw new IllegalArgumentException("El monto debe ser mayor a cero");if(monto.compareTo(c.getSaldoCuenta())>0)throw new IllegalArgumentException("El pago supera el saldo adeudado");c.setSaldoCuenta(c.getSaldoCuenta().subtract(monto));MovimientoCuenta m=guardar(c,MovimientoCuenta.Tipo.PAGO,monto,descripcion,null,usuarioId);auditoria.registrar(usuarioId,"COBRAR","CUENTA_CORRIENTE",clienteId,"Pago de "+monto);return dto(m);}
    @Transactional public void devolverCredito(Cliente c,BigDecimal monto,Venta venta,Long usuarioId){c.setSaldoCuenta(c.getSaldoCuenta().subtract(monto));guardar(c,MovimientoCuenta.Tipo.DEVOLUCION,monto,"Devolución de venta",venta,usuarioId);}
    @Transactional(readOnly=true)public List<MovimientoCuentaDTO> movimientos(Long clienteId){return movimientos.findByClienteIdOrderByFechaDesc(clienteId).stream().map(this::dto).toList();}
    private MovimientoCuenta guardar(Cliente c,MovimientoCuenta.Tipo tipo,BigDecimal monto,String descripcion,Venta venta,Long usuarioId){return movimientos.save(MovimientoCuenta.builder().cliente(c).fecha(LocalDateTime.now()).tipo(tipo).monto(monto).saldoResultante(c.getSaldoCuenta()).descripcion(descripcion).venta(venta).usuario(usuarioId==null?null:personas.findById(usuarioId).orElse(null)).build());}private Cliente cliente(Long id){return clientes.findById(id).orElseThrow(()->new IllegalArgumentException("Cliente inexistente"));}private MovimientoCuentaDTO dto(MovimientoCuenta m){return new MovimientoCuentaDTO(m.getId(),m.getFecha(),m.getTipo().name(),m.getMonto(),m.getSaldoResultante(),m.getDescripcion(),m.getVenta()==null?null:m.getVenta().getId());}}
